\displaystyle{\begin{aligned}
   \frac{7}{30} - \frac{5}{6}
        \amp =  \frac{7}{30} - \frac{25}{30} \\
        \amp = \frac{7 - 25}{30} \\
        \amp = \frac{-18}{30} \amp  \hbox{We can reduce this by dividing 6 into both the numerator and the denominator.
}\\
        \amp = -\frac{3}{5}
\end{aligned}
